            // Each assembly represents a domain
            policy.MapAssemblyToDomain("MyApp.Orders", "Orders");
            policy.MapAssemblyToDomain("MyApp.Inventory", "Inventory");
            policy.MapAssemblyToDomain("MyApp.Shipping", "Shipping");

