                        Title = $"Emits {eventFlow.EmittedEvents.Count} events, triggers {eventFlow.EventHandlers.Count} handlers",
                        Arguments = new object[] { eventFlow }
                    }
                });
            }
        }

        return codeLenses.ToArray();
    }
